module multi_8bit
(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

    reg [15:0] partial_product;
    reg [3:0] shift_count;

    always @(*) begin
        partial_product = 0;
        shift_count = 0;

        for (int i = 0; i < 8; i++) begin
            if (B[i]) begin
                partial_product = partial_product + (A << shift_count);
            end
            shift_count = shift_count + 1;
        end

        product = partial_product;
    end
endmodule
